/**
 * Generate OpenRouter firewall config.
 *
 * Data source: https://openrouter.ai/docs/api-reference
 *
 * OpenRouter uses Bearer-token authentication on
 * `https://openrouter.ai/api/...`.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://openrouter.ai/docs/api-reference";
// Format: sk-or-v1- + 64 chars
const PLACEHOLDER_VALUE =
  "sk-or-v1-CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from OpenRouter API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:openrouter",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const openrouterFirewall = {",
    '  name: "openrouter",',
    '  description: "OpenRouter API",',
    "  placeholders: {",
    `    OPENROUTER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://openrouter.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.OPENROUTER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating OpenRouter firewall config...");
  const ts = generateTypeScript();
  writeOutput("openrouter", ts, import.meta.dirname);
}
